tasks.solution:
from flask import Flask, jsonify

app = Flask(__name__)


@app.route("/")
def home():
    return "Hello from the Capstone Flask app!"


@app.route("/api")
def api():
    return jsonify({
        "message": "Hello, API!",
        "service": "capstone-flask",
        "version": "1.0.0"
    })


@app.route("/healthz")
def healthz():
    return jsonify({"status": "ok"}), 200


if __name__ == "__main__":
    app.run(host="0.0.0.0", port=5000)

# --- 검증 명령 (두 번째 터미널에서 실행) ---
# curl http://localhost:5000/
# 예상: Hello from the Capstone Flask app!
#
# curl http://localhost:5000/api
# 예상: {"message":"Hello, API!","service":"capstone-flask","version":"1.0.0"}
#
# curl -i http://localhost:5000/healthz
# 예상 첫 줄: HTTP/1.1 200 OK
#      본문:  {"status":"ok"}

