# 전체 업데이트된 app.py
import sys
from flask import Flask, jsonify

app = Flask(__name__)


@app.route("/")
def home():
    return "Hello from the Capstone Flask app!"


@app.route("/api")
def api():
    return jsonify({
        "message": "Hello, API!",
        "service": "capstone-flask",
        "version": "1.0.0",
        "environment": "local",
        "python_version": sys.version.split()[0]  # 예: '3.11.9'
    })


@app.route("/healthz")
def healthz():
    return jsonify({"status": "ok"}), 200


if __name__ == "__main__":
    app.run(host="0.0.0.0", port=5000)

# --- 검증 ---
# curl http://localhost:5000/api
# 예상 출력 (일부):
# {"environment":"local","message":"Hello, API!","python_version":"3.11.9",
#  "service":"capstone-flask","version":"1.0.0"}
#
# curl -i http://localhost:5000/healthz
# 예상: HTTP/1.1 200 OK
